                          <button onClick={() => saveNote()} className={`w-full py-5 rounded-[20px] font-black uppercase tracking-widest flex items-center justify-center space-x-2 transition-all ${isSaving ? 'bg-green-600' : 'bg-orange-600'} text-white shadow-xl`}><Save size={24}/> <span>{isSaving ? "Saved" : t.saveNote}</span></button>
