                                 <button onClick={() => handleAiSubmit()} className={`p-3 rounded-full ${aiInput.trim() ? 'bg-purple-600 text-white shadow-md' : 'bg-gray-200 text-gray-400 dark:bg-white/5 dark:text-gray-500'}`}><Send size={22} /></button>
